import React, { useEffect, useState } from "react";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "./ui/Table";
// import { useNavigate } from "react-router-dom";
import {
  AlertDialogTrigger,
  AlertDialog,
  AlertDialogContent,
  AlertDialogHeader,
  AlertDialogDescription,
  AlertDialogTitle,
  AlertDialogFooter,
  AlertDialogCancel,
  AlertDialogAction,
} from "./ui/AlertDialog";

const BookList = () => {
  const [books, setBooks] = useState([]);
  // const navigate = useNavigate();
  useEffect(() => {
    fetch("http://localhost:3000/api/book")
      .then((response) => response.json())
      .then((data) => setBooks(data))
      .catch((error) => console.error("erro for the data fetching ", error));
  }, []);

  const handleClick = (id) => {
    console.log("you click" + id);
    // navigate(`/bookShow/${id}`);
  };
  return (
    <AlertDialog className="w-full h-screen flex justify-center my-5">
        <div className="container">
          <Table>
            <TableHeader className="bg-blue-300 text-white">
              <TableRow>
                <TableHead className="w-[100px]  hidden sm:flex">ID</TableHead>
                <TableHead>Title</TableHead>
                <TableHead>description</TableHead>
                <TableHead className="text-right">Nombre des page</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {books.map((book) => (
                <AlertDialogTrigger>
                  <TableRow
                    key={book._id}
                    className="cursor-pointer "
                    onClick={() => handleClick(book._id)}
                  >
                    <TableCell className="font-medium hidden sm:flex">
                      {book._id}
                    </TableCell>
                    <TableCell>{book.title}</TableCell>
                    <TableCell>{book.description}</TableCell>
                    <TableCell className="text-right">{book.page}</TableCell>
                  </TableRow>
                </AlertDialogTrigger>
              ))}
            </TableBody>
          </Table>
        </div>
      <AlertDialogContent>
        <AlertDialogHeader>
          <AlertDialogTitle>Are you absolutely sure?</AlertDialogTitle>
          <AlertDialogDescription>
            This action cannot be undone. This will permanently delete your
            account and remove your data from our servers.
          </AlertDialogDescription>
        </AlertDialogHeader>
        <AlertDialogFooter>
          <AlertDialogCancel>Cancel</AlertDialogCancel>
          <AlertDialogAction>Continue</AlertDialogAction>
        </AlertDialogFooter>
      </AlertDialogContent>
    </AlertDialog>
  );
};

export default BookList;
